(1, 1, 'Serengeti National Park', 'serengeti-national-park', NULL, 'destinations/WN835Z2GeGeJr8burSgC4Vkk5QgGSc9DkJzzlfi0.jpg', '2026-03-27 07:38:03', '2026-03-31 17:04:23', -2.333129618758, 34.833301110211, NULL, NULL, NULL, NULL, NULL, NULL),
(2, 1, 'Ngorongoro Crater', 'ngorongoro-crater', 'Ngorongoro Crater is one of the world’s largest intact volcanic calderas and a UNESCO World Heritage Site. Often referred to as “Africa’s Garden of Eden,” it hosts a dense population of wildlife including lions, rhinos, elephants, buffalos, and hippos. The crater’s unique ecosystem makes it a must-see on any Tanzania safari. With a mix of grasslands, forests, and lakes, it offers incredible game viewing all year round. The dry season (June to October) is best for visibility, while the green season (November to May) offers dramatic scenery.', 'destinations/HqMdNiFFepcNlQDKolaeVnfaIAzZbMkF1bHvBh4n.jpg', '2026-03-27 09:08:16', '2026-03-28 10:50:23', -3.1678071740471, 35.574599715477, NULL, NULL, NULL, NULL, NULL, NULL),
(3, 1, 'Arusha National Park', 'arusha-national-park', NULL, 'destinations/UjfJnNP4B26JfubB7AGOMygoTKZHBj2VgrrbVF6j.jpg', '2026-03-27 09:09:34', '2026-03-27 10:45:02', -3.2618037097742, 36.845206772718, NULL, NULL, NULL, NULL, NULL, NULL),
(4, 1, 'Arusha', 'arusha', NULL, 'destinations/BuM271d9OojuksaVdn77Djn9f7B58dSLRDxMmUfi.jpg', '2026-03-27 11:31:14', '2026-03-27 11:31:14', -3.369683, 36.688079, NULL, NULL, NULL, NULL, NULL, NULL),
(5, 1, 'Tarangire National Park', 'tarangire-national-park', NULL, 'destinations/FLPYMMs6VLHRHfbPIaBRrr9KdIh0OZtrKWRVHW57.jpg', '2026-03-27 11:34:18', '2026-03-27 11:34:18', -4.1626516815293, 36.089850597122, NULL, NULL, NULL, NULL, NULL, NULL),
(6, 1, 'Lake Manyara National Park', 'lake-manyara-national-park', NULL, 'destinations/FLPYMMs6VLHRHfbPIaBRrr9KdIh0OZtrKWRVHW57.jpg', '2026-03-27 12:36:52', '2026-04-02 12:01:28', -3.6076306401739, 35.757644630691, '{"fr":"Parc national du lac Manyara","de":"Lake Manyara Nationalpark","es":"Parque nacional del Lago Manyara"}', NULL, NULL, NULL, NULL, NULL);
