INSERT INTO `hero_slides` (`id`, `page_section_id`, `label`, `title`, `subtitle`, `image`, `button_text`, `button_link`, `next_up_text`, `bg_color`, `bg_image`, `image_alt`, `order`, `created_at`, `updated_at`) VALUES
(2, 13, '{"en":"LUXURY COLLECTION","fr":"COLLECTION LUXE","de":"LUXUS-KOLLEKTION","es":"COLECCI\u00d3N DE LUJO"}', '{"en":"Discover the Wild Heart of Tanzania","fr":"D\u00e9couvrez le C\u0153ur Sauvage de la Tanzanie","de":"Entdecken Sie das Wilde Herz Tansanias","es":"Descubra el Coraz\u00f3n Salvaje de Tanzania"}', '{"en":"Handcrafted luxury safaris through the Serengeti, Ngorongoro Crater, and beyond","fr":"Safaris de luxe sur mesure \u00e0 travers le Serengeti, le crat\u00e8re du Ngorongoro et au-del\u00e0","de":"Handgefertigte Luxus-Safaris durch die Serengeti, den Ngorongoro-Krater und dar\u00fcber hinaus","es":"Safaris de lujo artesanales por el Serengeti, el cr\u00e1ter del Ngorongoro y m\u00e1s all\u00e1"}', NULL, '{"en":"Explore Safaris","fr":"Explorer les Safaris","de":"Safaris Entdecken","es":"Explorar Safaris"}', '/en/safaris', '{"en":"Luxury Private Journeys","fr":"Voyages Priv\u00e9s de Luxe","de":"Luxus-Privatreisen","es":"Viajes Privados de Lujo"}', '#083321', NULL, 'Luxury safari in the Serengeti', 0, '2026-04-04 09:27:46', '2026-04-04 09:32:52'),
(3, 13, '{"en":"NEW EXPERIENCE","fr":"NOUVELLE EXP\u00c9RIENCE","de":"NEUES ERLEBNIS","es":"NUEVA EXPERIENCIA"}', '{"en":"Witness the Great Migration","fr":"Assistez \u00e0 la Grande Migration","de":"Erleben Sie die Gro\u00dfe Migration","es":"Sea Testigo de la Gran Migraci\u00f3n"}', '{"en":"Follow millions of wildebeest across the endless Serengeti plains","fr":"Suivez des millions de gnous \u00e0 travers les plaines infinies du Serengeti","de":"Folgen Sie Millionen von Gnus \u00fcber die endlosen Serengeti-Ebenen","es":"Siga millones de \u00f1us a trav\u00e9s de las interminables llanuras del Serengeti"}', NULL, '{"en":"View Migration Safaris","fr":"Voir les Safaris Migration","de":"Migrations-Safaris Ansehen","es":"Ver Safaris de Migraci\u00f3n"}', '/en/safaris', '{"en":"Zanzibar Beach Escape","fr":"Escapade Baln\u00e9aire \u00e0 Zanzibar","de":"Zanzibar Strandausflug","es":"Escapada a la Playa de Zanz\u00edbar"}', '#131414', NULL, 'Great wildebeest migration in Tanzania', 1, '2026-04-04 09:27:46', '2026-04-04 09:32:52'),
(4, 13, '{"en":"EXCLUSIVE","fr":"EXCLUSIF","de":"EXKLUSIV","es":"EXCLUSIVO"}', '{"en":"Zanzibar \u2014 Where Safari Meets the Sea","fr":"Zanzibar \u2014 O\u00f9 le Safari Rencontre la Mer","de":"Sansibar \u2014 Wo Safari das Meer Trifft","es":"Zanz\u00edbar \u2014 Donde el Safari se Encuentra con el Mar"}', '{"en":"End your adventure on pristine white-sand beaches and turquoise waters","fr":"Terminez votre aventure sur des plages de sable blanc immacul\u00e9","de":"Beenden Sie Ihr Abenteuer an unber\u00fchrten wei\u00dfen Sandstr\u00e4nden","es":"Termine su aventura en playas de arena blanca pr\u00edstina"}', NULL, '{"en":"Discover Zanzibar","fr":"D\u00e9couvrir Zanzibar","de":"Sansibar Entdecken","es":"Descubrir Zanz\u00edbar"}', '/en/safaris', '{"en":"Serengeti Luxury Camp","fr":"Camp de Luxe Serengeti","de":"Serengeti Luxus-Camp","es":"Campamento de Lujo Serengeti"}', '#083321', NULL, 'Zanzibar beach tropical paradise', 2, '2026-04-04 09:27:46', '2026-04-04 09:32:52');
