(2, 3, 'Mr Roger Emmanuel', 'scopkariah@gmail.com', '+255 758273300', NULL, NULL, NULL, 'axsdsdsdsdsdsd', 'new', '2026-03-31 15:30:11', '2026-03-31 15:30:11', 'inquiry', NULL);
INSERT INTO `itineraries` (`id`, `safari_package_id`, `day_number`, `title`, `description`, `accommodation`, `created_at`, `updated_at`, `destination_id`, `accommodation_id`, `image_path`, `title_translations`, `description_translations`) VALUES
(283, 2, 1, 'ARRIVAL DAY', 'Upon arrival at the airport, you will be greeted by a professional guide who will be waiting to assist you. After your long flight, we offer a selection of coffee, tea, or hot chocolate, served with delicious snacks to help you refresh. You will then be driven to your hotel for further relaxation. In the evening, your guide will provide a safari briefing to prepare you for the exciting journey ahead.', NULL, '2026-04-02 23:55:49', '2026-04-02 23:55:49', 4, NULL, NULL, '{"fr":"Date d''arriv\u00e9e","de":"Anreisetag g\u00fcltig","es":"Fecha de llegada:"}', '{"fr":"\u00c0 votre arriv\u00e9e \u00e0 l''a\u00e9roport, vous serez accueilli par un guide professionnel qui vous attendra pour vous aider. Apr\u00e8s votre long vol, nous vous proposons une s\u00e9lection de caf\u00e9, de th\u00e9 ou de chocolat chaud, servis avec de d\u00e9licieuses collations pour vous aider \u00e0 vous rafra\u00eechir. Vous serez ensuite conduit \u00e0 votre h\u00f4tel pour vous d\u00e9tendre davantage. Dans la soir\u00e9e, votre guide vous donnera un briefing sur le safari pour vous pr\u00e9parer au voyage passionnant qui vous attend.","de":"Bei Ihrer Ankunft am Flughafen werden Sie von einem professionellen Reiseleiter begr\u00fc\u00dft, der Ihnen gerne behilflich ist. Nach Ihrem langen Flug bieten wir Ihnen eine Auswahl an Kaffee, Tee oder hei\u00dfer Schokolade, serviert mit leckeren Snacks zur Erfrischung. Anschlie\u00dfend werden Sie zur weiteren Entspannung zu Ihrem Hotel gefahren. Am Abend bietet Ihnen Ihr Reiseleiter ein Safari-Briefing an, um Sie auf die aufregende Reise vorzubereiten.","es":"Al llegar al aeropuerto, ser\u00e1s recibido por un gu\u00eda profesional que te estar\u00e1 esperando para ayudarte. Despu\u00e9s de su largo vuelo, ofrecemos una selecci\u00f3n de caf\u00e9, t\u00e9 o chocolate caliente, servido con deliciosos bocadillos para ayudarlo a refrescarse. A continuaci\u00f3n, nos dirigiremos a nuestro hotel para relajarnos. Por la noche, el gu\u00eda ofrecer\u00e1 una sesi\u00f3n informativa de safari para prepararnos para el emocionante viaje que tenemos por delante."}'),
(284, 2, 2, 'ARUSHA NATIONAL PARK', 'After a leisurely breakfast at the lodge, you will receive a brief safari orientation, where we’ll cover all the essential information and answer any questions you may have about your upcoming adventure.
