(14, 2, 'icon_features', 1, 1, '{"heading":{"en":"Why Choose Lomo Africa","fr":"Pourquoi Choisir Lomo Africa","de":"Warum Lomo Africa W\u00e4hlen","es":"Por Qu\u00e9 Elegir Lomo Africa"},"subheading":{"en":"Crafting unforgettable safari experiences since day one","fr":"Cr\u00e9er des exp\u00e9riences de safari inoubliables depuis le premier jour","de":"Unvergessliche Safari-Erlebnisse seit dem ersten Tag","es":"Creando experiencias de safari inolvidables desde el primer d\u00eda"},"columns":"4","bg_color":"#000000","items":[{"icon":"heart","title":{"en":"Handcrafted Safaris","fr":"Safaris Sur Mesure","de":"Handgefertigte Safaris","es":"Safaris Artesanales"},"description":{"en":"Every journey is tailor-made to your dreams and preferences","fr":"Chaque voyage est con\u00e7u sur mesure selon vos r\u00eaves","de":"Jede Reise wird nach Ihren Tr\u00e4umen ma\u00dfgeschneidert","es":"Cada viaje se adapta a sus sue\u00f1os y preferencias"}},{"icon":"globe","title":{"en":"Local Experts","fr":"Experts Locaux","de":"Lokale Experten","es":"Expertos Locales"},"description":{"en":"Born and raised in Tanzania \u2014 we know every hidden gem","fr":"N\u00e9s et \u00e9lev\u00e9s en Tanzanie \u2014 nous connaissons chaque tr\u00e9sor cach\u00e9","de":"Geboren und aufgewachsen in Tansania \u2014 wir kennen jeden verborgenen Schatz","es":"Nacidos y criados en Tanzania \u2014 conocemos cada joya oculta"}},{"icon":"shield","title":{"en":"Luxury Lodges","fr":"Lodges de Luxe","de":"Luxus-Lodges","es":"Lodges de Lujo"},"description":{"en":"Hand-picked 5-star lodges and tented camps in the wilderness","fr":"Lodges 5 \u00e9toiles s\u00e9lectionn\u00e9s dans la nature sauvage","de":"Handverlesene 5-Sterne-Lodges und Zeltcamps in der Wildnis","es":"Lodges de 5 estrellas seleccionados en la naturaleza"}},{"icon":"clock","title":{"en":"24\/7 Support","fr":"Support 24\/7","de":"24\/7 Unterst\u00fctzung","es":"Soporte 24\/7"},"description":{"en":"Round-the-clock assistance from booking to your last sunset","fr":"Assistance 24h\/24 de la r\u00e9servation \u00e0 votre dernier coucher de soleil","de":"Rund-um-die-Uhr-Betreuung von der Buchung bis zum letzten Sonnenuntergang","es":"Asistencia las 24 horas desde la reserva hasta su \u00faltima puesta de sol"}}]}', '2026-04-04 09:27:46', '2026-04-04 09:32:52'),
(15, 2, 'safari_grid', 2, 1, '{"heading":{"en":"Featured Safari Journeys","fr":"Safaris en Vedette","de":"Ausgew\u00e4hlte Safari-Reisen","es":"Safaris Destacados"},"subheading":{"en":"Our most sought-after luxury experiences across Tanzania","fr":"Nos exp\u00e9riences de luxe les plus recherch\u00e9es en Tanzanie","de":"Unsere gefragtesten Luxuserlebnisse in Tansania","es":"Nuestras experiencias de lujo m\u00e1s buscadas en Tanzania"},"count":6,"featured_only":"1","columns":"3","category_filter":null,"show_rating":"1","slider_autoplay":"1"}', '2026-04-04 09:27:46', '2026-04-04 09:32:52'),
(16, 2, 'destination_showcase', 3, 1, '{"heading":{"en":"Explore Tanzania''s Finest","fr":"Explorez le Meilleur de la Tanzanie","de":"Entdecken Sie Tansanias Bestes","es":"Explore lo Mejor de Tanzania"},"subheading":{"en":"From the endless Serengeti to the spice island of Zanzibar","fr":"Des plaines infinies du Serengeti \u00e0 l''\u00eele aux \u00e9pices de Zanzibar","de":"Von der endlosen Serengeti bis zur Gew\u00fcrzinsel Sansibar","es":"Desde el interminable Serengeti hasta la isla de las especias de Zanz\u00edbar"},"count":3,"featured_only":"1","columns":"3","category_filter":null,"show_rating":"1","slider_autoplay":"1"}', '2026-04-04 09:27:46', '2026-04-04 09:33:21'),
(17, 2, 'split_hero', 4, 1, '{"heading":{"en":"Experience Africa Beyond Expectations","fr":"Vivez l''Afrique Au-Del\u00e0 des Attentes","de":"Erleben Sie Afrika Jenseits Aller Erwartungen","es":"Viva \u00c1frica M\u00e1s All\u00e1 de las Expectativas"},"subheading":{"en":"A journey designed around you","fr":"Un voyage con\u00e7u autour de vous","de":"Eine Reise, die um Sie herum gestaltet wurde","es":"Un viaje dise\u00f1ado en torno a usted"},"body":{"en":"For over a decade, we have been guiding discerning travelers through Tanzania''s most extraordinary landscapes. Every safari we craft is a deeply personal journey \u2014 from private game drives at dawn to candlelit dinners under the stars. This is not just a trip. This is your story, written in the wild.","fr":"Depuis plus d''une d\u00e9cennie, nous guidons des voyageurs exigeants \u00e0 travers les paysages les plus extraordinaires de Tanzanie. Chaque safari que nous cr\u00e9ons est un voyage profond\u00e9ment personnel \u2014 des safaris priv\u00e9s \u00e0 l''aube aux d\u00eeners aux chandelles sous les \u00e9toiles.","de":"Seit \u00fcber einem Jahrzehnt f\u00fchren wir anspruchsvolle Reisende durch Tansanias au\u00dfergew\u00f6hnlichste Landschaften. Jede Safari, die wir gestalten, ist eine zutiefst pers\u00f6nliche Reise \u2014 von privaten Pirschfahrten bei Morgengrauen bis zu Abendessen bei Kerzenschein unter den Sternen.","es":"Durante m\u00e1s de una d\u00e9cada, hemos guiado a viajeros exigentes a trav\u00e9s de los paisajes m\u00e1s extraordinarios de Tanzania. Cada safari que creamos es un viaje profundamente personal \u2014 desde safaris privados al amanecer hasta cenas a la luz de las velas bajo las estrellas."},"button_text":{"en":"Plan Your Safari","fr":"Planifiez Votre Safari","de":"Planen Sie Ihre Safari","es":"Planifique Su Safari"},"button_url":"\/en\/plan-safari","layout":"image_right","image":"safaris\/Sy6BdtdamfKGcVioraGTB6dbwtjfjZwRwVyYibru.png","bg_color":"#083321"}', '2026-04-04 09:27:46', '2026-04-04 09:35:26'),
(18, 2, 'testimonial_slider', 5, 1, '{"heading":{"en":"What Our Guests Say","fr":"Ce Que Disent Nos Invit\u00e9s","de":"Was Unsere G\u00e4ste Sagen","es":"Lo Que Dicen Nuestros Hu\u00e9spedes"},"subheading":{"en":"Real stories from travelers who experienced the magic","fr":"De vraies histoires de voyageurs qui ont v\u00e9cu la magie","de":"Echte Geschichten von Reisenden, die die Magie erlebt haben","es":"Historias reales de viajeros que experimentaron la magia"},"count":6,"featured_only":"1","columns":"3","category_filter":null,"show_rating":"1","slider_autoplay":"1"}', '2026-04-04 09:27:46', '2026-04-04 09:32:52'),
(19, 2, 'image_gallery', 6, 1, '{"heading":{"en":"Safari Moments","fr":"Moments Safari","de":"Safari-Momente","es":"Momentos de Safari"},"gallery_layout":"grid","lightbox":"1","images":"itineraries\/uk3f81rGtyx0ofjGzG0pifZg0ze5UuXNkNNt9OTQ.jpg, destinations\/BuM271d9OojuksaVdn77Djn9f7B58dSLRDxMmUfi.jpg, destinations\/HqMdNiFFepcNlQDKolaeVnfaIAzZbMkF1bHvBh4n.jpg, destinations\/WN835Z2GeGeJr8burSgC4Vkk5QgGSc9DkJzzlfi0.jpg, countries\/b3pjg3h4UktOoCh0ISZ9YcnsiEocC599rWwqrfkp.png, destinations\/BuM271d9OojuksaVdn77Djn9f7B58dSLRDxMmUfi.jpg"}', '2026-04-04 09:27:46', '2026-04-04 09:43:32'),
(20, 2, 'cta_banner', 7, 1, '{"heading":{"en":"Start Planning Your Dream Safari","fr":"Commencez \u00e0 Planifier Votre Safari de R\u00eave","de":"Beginnen Sie mit der Planung Ihrer Traumsafari","es":"Comience a Planificar Su Safari So\u00f1ado"},"subheading":{"en":"Let our experts craft a bespoke journey tailored to your every wish. No templates \u2014 just your story, written in the wild.","fr":"Laissez nos experts cr\u00e9er un voyage sur mesure adapt\u00e9 \u00e0 chacun de vos souhaits.","de":"Lassen Sie unsere Experten eine ma\u00dfgeschneiderte Reise nach Ihren W\u00fcnschen gestalten.","es":"Deje que nuestros expertos elaboren un viaje a medida adaptado a cada uno de sus deseos."},"button_text":{"en":"Plan My Safari","fr":"Planifier Mon Safari","de":"Meine Safari Planen","es":"Planificar Mi Safari"},"button_url":"\/en\/plan-safari","bg_color":"#083321","bg_image":null}', '2026-04-04 09:27:46', '2026-04-04 09:32:52'),
(21, 2, 'blog', 8, 1, '{"heading":{"en":"Safari Insights & Stories","fr":"Aper\u00e7us & Histoires de Safari","de":"Safari-Einblicke & Geschichten","es":"Perspectivas e Historias de Safari"},"subheading":{"en":"Expert tips, travel guides, and tales from the African bush","fr":"Conseils d''experts, guides de voyage et r\u00e9cits de la brousse africaine","de":"Expertentipps, Reisef\u00fchrer und Geschichten aus dem afrikanischen Busch","es":"Consejos de expertos, gu\u00edas de viaje e historias de la sabana africana"},"count":3,"featured_only":"1","columns":"3","category_filter":null,"show_rating":"1","slider_autoplay":"1"}', '2026-04-04 09:27:46', '2026-04-04 09:32:52'),
(22, 1, 'split_hero', 0, 1, '{"heading":{"en":"Your Journey. Our Passion.","fr":"Votre Voyage. Notre Passion.","de":"Ihre Reise. Unsere Leidenschaft.","es":"Tu Viaje. Nuestra Pasi\u00f3n."},"subheading":{"en":"A Safari That Changes Lives","fr":"Un Safari Qui Change des Vies","de":"Eine Safari, Die Leben Ver\u00e4ndert","es":"Un Safari Que Cambia Vidas"},"body":{"en":"<p>Lomo Tanzania Safaris is a locally owned and operated safari company based in Tanzania, offering authentic and personalized safari experiences across the country''s most iconic destinations.<\/p>","fr":"<p>Lomo Tanzania Safaris est une entreprise de safari locale bas\u00e9e en Tanzanie, offrant des exp\u00e9riences de safari authentiques et personnalis\u00e9es \u00e0 travers les destinations les plus embl\u00e9matiques du pays.<\/p>","de":"<p>Lomo Tanzania Safaris ist ein lokal gef\u00fchrtes Safariunternehmen mit Sitz in Tansania, das authentische und personalisierte Safarierlebnisse an den ikonischsten Reisezielen des Landes anbietet.<\/p>","es":"<p>Lomo Tanzania Safaris es una empresa de safari local con sede en Tanzania, que ofrece experiencias de safari aut\u00e9nticas y personalizadas en los destinos m\u00e1s ic\u00f3nicos del pa\u00eds.<\/p>"},"button_text":{"en":"Start Planning Your Safari","fr":"Planifiez Votre Safari","de":"Planen Sie Ihre Safari","es":"Planifica Tu Safari"},"button_url":"\/custom-tour","layout":"image_right","image":"destinations\/WN835Z2GeGeJr8burSgC4Vkk5QgGSc9DkJzzlfi0.jpg","bg_color":"#000000"}', '2026-04-04 10:25:57', '2026-04-04 10:30:02'),
(23, 1, 'image_text', 1, 1, '{"heading":{"en":"Founded on Passion, Built on Experience","fr":"Fond\u00e9 sur la Passion, Construit sur l''Exp\u00e9rience","de":"Gegr\u00fcndet aus Leidenschaft, Aufgebaut auf Erfahrung","es":"Fundada en la Pasi\u00f3n, Construida en la Experiencia"},"body":{"en":"<p>Lomo Tanzania Safaris was founded by Mr. Erasto, a passionate Tanzanian wildlife guide with over 19 years of experience in the safari industry.<\/p><p>Born and raised in Tanzania, Erasto began his journey in 2003 at Selous Game Reserve. His deep love for wildlife led him to train at Mwewe Training College in Serengeti, where he qualified as a ranger.<\/p><p>Over the years, he worked with luxury camps across Serengeti, mastering the art of guiding and delivering unforgettable safari experiences.<\/p><p>During one safari, he met a Dutch couple who shared his vision \u2014 together, they built Lomo Tanzania Safaris.<\/p>","fr":"<p>Lomo Tanzania Safaris a \u00e9t\u00e9 fond\u00e9 par M. Erasto, un guide passionn\u00e9 de la faune tanzanienne avec plus de 19 ans d''exp\u00e9rience dans l''industrie du safari.<\/p><p>N\u00e9 et \u00e9lev\u00e9 en Tanzanie, Erasto a commenc\u00e9 son parcours en 2003 \u00e0 la R\u00e9serve de Selous. Son amour profond pour la faune l''a conduit \u00e0 se former au Mwewe Training College dans le Serengeti, o\u00f9 il a obtenu son dipl\u00f4me de ranger.<\/p><p>Au fil des ann\u00e9es, il a travaill\u00e9 avec des camps de luxe \u00e0 travers le Serengeti, ma\u00eetrisant l''art du guidage et offrant des exp\u00e9riences de safari inoubliables.<\/p><p>Lors d''un safari, il a rencontr\u00e9 un couple n\u00e9erlandais qui partageait sa vision \u2014 ensemble, ils ont construit Lomo Tanzania Safaris.<\/p>","de":"<p>Lomo Tanzania Safaris wurde von Herrn Erasto gegr\u00fcndet, einem leidenschaftlichen tansanischen Wildlife-Guide mit \u00fcber 19 Jahren Erfahrung in der Safari-Branche.<\/p><p>In Tansania geboren und aufgewachsen, begann Erasto seine Reise 2003 im Selous Game Reserve. Seine tiefe Liebe zur Tierwelt f\u00fchrte ihn zum Mwewe Training College im Serengeti, wo er sich als Ranger qualifizierte.<\/p><p>Im Laufe der Jahre arbeitete er mit Luxuscamps im Serengeti zusammen und perfektionierte die Kunst des Guidings und das Liefern unvergesslicher Safari-Erlebnisse.<\/p><p>W\u00e4hrend einer Safari traf er ein niederl\u00e4ndisches Paar, das seine Vision teilte \u2014 gemeinsam bauten sie Lomo Tanzania Safaris auf.<\/p>","es":"<p>Lomo Tanzania Safaris fue fundada por el Sr. Erasto, un apasionado gu\u00eda de vida silvestre tanzano con m\u00e1s de 19 a\u00f1os de experiencia en la industria del safari.<\/p><p>Nacido y criado en Tanzania, Erasto comenz\u00f3 su viaje en 2003 en la Reserva de Selous. Su profundo amor por la vida silvestre lo llev\u00f3 a formarse en el Mwewe Training College en Serengeti, donde se calific\u00f3 como ranger.<\/p><p>A lo largo de los a\u00f1os, trabaj\u00f3 con campamentos de lujo en Serengeti, dominando el arte de guiar y ofrecer experiencias de safari inolvidables.<\/p><p>Durante un safari, conoci\u00f3 a una pareja holandesa que compart\u00eda su visi\u00f3n \u2014 juntos, construyeron Lomo Tanzania Safaris.<\/p>"},"image":"countries\/b3pjg3h4UktOoCh0ISZ9YcnsiEocC599rWwqrfkp.png","layout":"image_left"}', '2026-04-04 10:25:57', '2026-04-04 10:30:02'),
(24, 1, 'highlight', 2, 1, '[]', '2026-04-04 10:25:57', '2026-04-04 10:30:02'),
(25, 1, 'two_column_feature', 3, 1, '[]', '2026-04-04 10:25:57', '2026-04-04 10:30:02'),
(26, 1, 'icon_features', 4, 1, '{"heading":{"en":"Why Choose Us","fr":"Pourquoi Nous Choisir","de":"Warum Uns W\u00e4hlen","es":"Por Qu\u00e9 Elegirnos"},"subheading":{"en":"Five reasons travelers trust Lomo Tanzania Safaris","fr":"Cinq raisons pour lesquelles les voyageurs font confiance \u00e0 Lomo Tanzania Safaris","de":"F\u00fcnf Gr\u00fcnde, warum Reisende Lomo Tanzania Safaris vertrauen","es":"Cinco razones por las que los viajeros conf\u00edan en Lomo Tanzania Safaris"},"columns":"3","bg_color":"#000000","items":[{"icon":"shield","title":{"en":"Locally Owned Experts","fr":"Experts Locaux","de":"Lokale Experten","es":"Expertos Locales"},"description":{"en":"Born and raised in Tanzania, our team knows every trail, every animal behavior, and every hidden gem across the country.","fr":"N\u00e9s et \u00e9lev\u00e9s en Tanzanie, notre \u00e9quipe conna\u00eet chaque sentier, chaque comportement animal et chaque joyau cach\u00e9 du pays.","de":"In Tansania geboren und aufgewachsen, kennt unser Team jeden Pfad, jedes Tierverhalten und jedes versteckte Juwel des Landes.","es":"Nacidos y criados en Tanzania, nuestro equipo conoce cada sendero, cada comportamiento animal y cada joya oculta del pa\u00eds."}},{"icon":"map","title":{"en":"Tailor-Made Safaris","fr":"Safaris Sur Mesure","de":"Ma\u00dfgeschneiderte Safaris","es":"Safaris a Medida"},"description":{"en":"Every safari is designed around your interests, pace, and budget. No cookie-cutter itineraries \u2014 only personalized experiences.","fr":"Chaque safari est con\u00e7u autour de vos int\u00e9r\u00eats, votre rythme et votre budget. Pas d''itin\u00e9raires standardis\u00e9s \u2014 uniquement des exp\u00e9riences personnalis\u00e9es.","de":"Jede Safari wird nach Ihren Interessen, Ihrem Tempo und Ihrem Budget gestaltet. Keine Standardreisen \u2014 nur personalisierte Erlebnisse.","es":"Cada safari est\u00e1 dise\u00f1ado en torno a sus intereses, ritmo y presupuesto. Sin itinerarios est\u00e1ndar \u2014 solo experiencias personalizadas."}},{"icon":"heart","title":{"en":"Community Impact","fr":"Impact Communautaire","de":"Gemeinschaftliche Wirkung","es":"Impacto Comunitario"},"description":{"en":"Every booking directly supports education, healthcare, and development in local Tanzanian communities.","fr":"Chaque r\u00e9servation soutient directement l''\u00e9ducation, la sant\u00e9 et le d\u00e9veloppement des communaut\u00e9s locales tanzaniennes.","de":"Jede Buchung unterst\u00fctzt direkt Bildung, Gesundheitswesen und Entwicklung in lokalen tansanischen Gemeinden.","es":"Cada reserva apoya directamente la educaci\u00f3n, la salud y el desarrollo en las comunidades locales de Tanzania."}},{"icon":"camera","title":{"en":"Attention to Detail","fr":"Attention aux D\u00e9tails","de":"Liebe zum Detail","es":"Atenci\u00f3n al Detalle"},"description":{"en":"From your first inquiry to your last sunset game drive, we ensure every detail is taken care of with precision and warmth.","fr":"De votre premi\u00e8re demande \u00e0 votre dernier safari au coucher du soleil, nous veillons \u00e0 ce que chaque d\u00e9tail soit pris en charge avec pr\u00e9cision et chaleur.","de":"Von Ihrer ersten Anfrage bis zu Ihrer letzten Pirschfahrt bei Sonnenuntergang sorgen wir daf\u00fcr, dass jedes Detail mit Pr\u00e4zision und W\u00e4rme erledigt wird.","es":"Desde su primera consulta hasta su \u00faltimo safari al atardecer, nos aseguramos de que cada detalle sea atendido con precisi\u00f3n y calidez."}},{"icon":"globe","title":{"en":"Sustainable Tourism","fr":"Tourisme Durable","de":"Nachhaltiger Tourismus","es":"Turismo Sostenible"},"description":{"en":"We are committed to protecting Tanzania''s wildlife and ecosystems through responsible and sustainable travel practices.","fr":"Nous nous engageons \u00e0 prot\u00e9ger la faune et les \u00e9cosyst\u00e8mes de la Tanzanie gr\u00e2ce \u00e0 des pratiques de voyage responsables et durables.","de":"Wir setzen uns f\u00fcr den Schutz der Tierwelt und \u00d6kosysteme Tansanias durch verantwortungsvolle und nachhaltige Reisepraktiken ein.","es":"Estamos comprometidos a proteger la vida silvestre y los ecosistemas de Tanzania a trav\u00e9s de pr\u00e1cticas de viaje responsables y sostenibles."}}]}', '2026-04-04 10:25:57', '2026-04-04 10:30:02'),
(27, 1, 'destinations', 5, 1, '{"heading":{"en":"Where We Take You","fr":"O\u00f9 Nous Vous Emmenons","de":"Wohin Wir Sie Bringen","es":"Ad\u00f3nde Te Llevamos"},"subheading":{"en":"Explore Tanzania''s most iconic destinations with expert local guides","fr":"Explorez les destinations les plus embl\u00e9matiques de Tanzanie avec des guides locaux experts","de":"Erkunden Sie Tansanias ikonischste Reiseziele mit erfahrenen lokalen Guides","es":"Explora los destinos m\u00e1s ic\u00f3nicos de Tanzania con gu\u00edas locales expertos"},"count":6,"featured_only":"1","columns":"3","category_filter":null,"show_rating":"1","slider_autoplay":"1"}', '2026-04-04 10:25:57', '2026-04-04 10:30:02'),
(28, 1, 'experience_grid', 6, 1, '[]', '2026-04-04 10:25:57', '2026-04-04 10:30:02'),
(29, 1, 'cta_banner', 7, 1, '{"heading":{"en":"Join a Journey That Changes Lives","fr":"Rejoignez un Voyage Qui Change des Vies","de":"Werden Sie Teil einer Reise, Die Leben Ver\u00e4ndert","es":"\u00danete a un Viaje Que Cambia Vidas"},"subheading":{"en":"Every safari is more than a trip \u2014 it''s a connection, an experience, and an impact.","fr":"Chaque safari est plus qu''un voyage \u2014 c''est une connexion, une exp\u00e9rience et un impact.","de":"Jede Safari ist mehr als eine Reise \u2014 es ist eine Verbindung, ein Erlebnis und eine Wirkung.","es":"Cada safari es m\u00e1s que un viaje \u2014 es una conexi\u00f3n, una experiencia y un impacto."},"button_text":{"en":"Start Planning","fr":"Commencer \u00e0 Planifier","de":"Jetzt Planen","es":"Empezar a Planificar"},"button_url":"\/custom-tour","bg_color":"#083321","bg_image":null}', '2026-04-04 10:25:57', '2026-04-04 10:30:02');
