INSERT INTO `safari_packages` (`id`, `title`, `slug`, `short_description`, `description`, `duration`, `tour_type`, `category`, `difficulty`, `price`, `currency`, `featured_image`, `video_url`, `map_image`, `map_embed`, `status`, `created_at`, `updated_at`, `featured`, `tour_type_id`, `category_id`, `highlights`, `included`, `excluded`, `highlights_title`, `highlights_intro`, `inclusions_title`, `inclusions_intro`, `overview_title`, `seasonal_pricing`, `title_translations`, `short_description_translations`, `description_translations`, `highlights_translations`, `meta_title`, `meta_description`, `meta_keywords`, `og_image`, `highlights_title_translations`, `highlights_intro_translations`, `inclusions_title_translations`, `inclusions_intro_translations`, `overview_title_translations`, `featured_order`, `featured_label`) VALUES
(2, '8 Days Tanzania Luxury Safari', '8-days-tanzania-luxury-safari', 'Embark on an extraordinary 8-day luxury safari through Tanzania’s most iconic destinations, beginning in the vibrant city of Arusha and venturing deep into the heart of the Northern Safari Circuit. This unforgettable journey blends breathtaking landscapes, extraordinary wildlife encounters, and rich cultural experiences, all while indulging in the comfort of Tanzania’s finest lodges and camps.', '<p>&lt;p&gt;&amp;lt;p&amp;gt;&amp;amp;lt;p&amp;amp;gt;&amp;amp;amp;lt;p&amp;amp;amp;gt;&amp;amp;amp;amp;lt;p&amp;amp;amp;amp;gt;Embark on an extraordinary 8-day luxury safari through Tanzania’s most iconic destinations, beginning in the vibrant city of Arusha and venturing deep into the heart of the Northern Safari Circuit. This unforgettable journey blends breathtaking landscapes, extraordinary wildlife encounters, and rich cultural experiences, all while indulging in the comfort of Tanzania’s finest lodges and camps.&amp;amp;amp;amp;lt;/p&amp;amp;amp;amp;gt;&amp;amp;amp;lt;/p&amp;amp;amp;gt;&amp;amp;lt;/p&amp;amp;gt;&amp;lt;/p&amp;gt;&lt;/p&gt;</p>', '8 Days / 7 Nights', NULL, NULL, NULL, NULL, 'USD', 'safaris/Sy6BdtdamfKGcVioraGTB6dbwtjfjZwRwVyYibru.png', NULL, NULL, NULL, 'published', '2026-03-27 08:54:31', '2026-04-02 23:55:49', 1, NULL, NULL, NULL, NULL, NULL, 'Highlights', 'The standout moments built into this safari.', 'Inclusions & Exclusions', 'A clear view of what is covered and what to plan for separately.', 'Experience Overview', NULL, '{"fr":"Safari de luxe en Tanzanie de 8 jours"}', '{"fr":"Embarquez pour un extraordinaire safari de luxe de 8 jours \u00e0 travers les destinations les plus embl\u00e9matiques de Tanzanie, en commen\u00e7ant par la ville anim\u00e9e d''Arusha et en vous aventurant au c\u0153ur du circuit Northern Safari. Ce voyage inoubliable allie des paysages \u00e0 couper le souffle, des rencontres extraordinaires avec la faune et des exp\u00e9riences culturelles riches, tout en profitant du confort des meilleurs lodges et camps de Tanzanie."}', '{"fr":"&lt;p&gt; &amp;lt;p&amp;gt\u00a0;Embarquez pour un extraordinaire safari de luxe de 8 jours \u00e0 travers les destinations les plus embl\u00e9matiques de Tanzanie, en commen\u00e7ant par la ville anim\u00e9e d''Arusha et en vous aventurant au c\u0153ur du circuit Northern Safari. Ce voyage inoubliable allie des paysages \u00e0 couper le souffle, des rencontres extraordinaires avec la faune et des exp\u00e9riences culturelles riches, tout en profitant du confort des meilleurs lodges et camps de Tanzanie. &amp;lt;\/p&amp;gt\u00a0;&lt;\/p&gt;"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"fr":"Aper\u00e7u de l''exp\u00e9rience"}', 0, NULL),
(3, '6-Days Tanzania Safari Adventure', '6-days-tanzania-safari-adventure', 'This 6-day safari &amp;lt;/strong&amp;gt;takes you on an unforgettable journey through Tanzania’s most iconic parks: Tarangire, renowned for its elephants and baobab trees; the Serengeti, where the Great Migration unfolds amidst diverse predators;', '<p>arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania arusha tanzania i love tanzania </p>', '6 Days/ 5 Nights', NULL, NULL, NULL, NULL, 'USD', 'destinations/FLPYMMs6VLHRHfbPIaBRrr9KdIh0OZtrKWRVHW57.jpg', NULL, NULL, NULL, 'published', '2026-03-27 13:11:27', '2026-04-03 07:27:12', 1, 1, 1, '["Big Five safari","Luxury lodges","Serengeti migration"]', '["asasasasasasas","asasasas","as","asasas","as","as","asas","as","as","sasas"]', '["noooooooo","noooooooooooooo","nooooooooo","noooooooooooo","nooooooooooooooooooooooooo","nooooooooooooooooo","nnoooooooooooooooooo","ooooonoooooooooooooo"]', 'Highlights', 'The standout moments built into this safari.', 'Inclusions & Exclusions', 'A clear view of what is covered and what to plan for separately.', 'Tanzania Safari Adventure', NULL, '{"fr":"Aventure safari de 6 jours en Tanzanie","de":"6-t\u00e4giges Safari-Abenteuer in Tansania: Tarangire, Serengeti, Ngorongoro & Lake Manyara","es":"Aventura de safari de 6 d\u00edas por Tanzania: Tarangire, Serengeti, Ngorongoro y el lago Manyara"}', '{"fr":"Ce safari de 6 jours &amp;lt;\/strong&amp;gt\u00a0; vous emm\u00e8ne dans un voyage inoubliable \u00e0 travers les parcs les plus embl\u00e9matiques de Tanzanie\u00a0: Tarangire, r\u00e9put\u00e9 pour ses \u00e9l\u00e9phants et ses baobabs\u00a0; le Serengeti, o\u00f9 la Grande Migration se d\u00e9roule au milieu de divers pr\u00e9dateurs\u00a0;","de":"Diese 6-t\u00e4gige Safari &amp;lt;\/strong&amp;gt;nimmt Sie mit auf eine unvergessliche Reise durch Tansanias ber\u00fchmteste Parks: Tarangire, bekannt f\u00fcr seine Elefanten und Baobab-B\u00e4ume; die Serengeti, wo sich die Gro\u00dfe Migration inmitten verschiedener Raubtiere entfaltet;","es":"Este safari de 6 d\u00edas &amp;lt;\/strong&amp;gt; te lleva en un viaje inolvidable por los parques m\u00e1s emblem\u00e1ticos de Tanzania: Tarangire, famoso por sus elefantes y baobabs; el Serengeti, donde la Gran Migraci\u00f3n se desarrolla en medio de diversos depredadores;"}', '{"fr":"&lt;p&gt;Notre itin\u00e9raire soigneusement con\u00e7u d\u00e9crit chaque jour de votre voyage en d\u00e9tail, assurant une exp\u00e9rience de voyage transparente. De l''arriv\u00e9e au d\u00e9part, chaque \u00e9tape a \u00e9t\u00e9 soigneusement planifi\u00e9e pour maximiser le confort, la d\u00e9couverte et la valeur.","de":"&lt;p&gt;Unsere sorgf\u00e4ltig gestaltete Reiseroute beschreibt jeden Tag Ihrer Reise im Detail und sorgt f\u00fcr ein nahtloses Reiseerlebnis. Von der Ankunft bis zur Abreise wurde jeder Schritt sorgf\u00e4ltig geplant, um Komfort, Entdeckung und Wert zu maximieren","es":"&lt;p&gt;Nuestro itinerario cuidadosamente dise\u00f1ado describe cada d\u00eda de tu viaje en detalle, lo que garantiza una experiencia de viaje perfecta. Desde la llegada hasta la salida, cada paso se ha planificado cuidadosamente para maximizar la comodidad, el descubrimiento y el valor."}', NULL, NULL, NULL, NULL, NULL, '{"fr":"Nouveaut\u00e9s","de":"Highlights","es":"Destacados"}', '{"fr":"Les moments forts de ce safari.","de":"Die herausragenden Momente, die in diese Safari eingebaut sind.","es":"Los momentos m\u00e1s destacados de este safari."}', '{"fr":"Inclusions et exclusions","de":"Ein- und Ausschl\u00fcsse","es":"Inclusiones\/Exclusiones"}', '{"fr":"Une vision claire de ce qui est couvert et de ce qu''il faut planifier s\u00e9par\u00e9ment.","de":"Ein klarer \u00dcberblick dar\u00fcber, was abgedeckt ist und was separat zu planen ist.","es":"Una visi\u00f3n clara de lo que est\u00e1 cubierto y qu\u00e9 planificar por separado."}', '{"fr":"Aventure safari en Tanzanie","de":"Safari-Abenteuer in Tansania","es":"Aventura de safari en Tanzania"}', 0, NULL);
